/**
 * Contrato de Registro de Conformidade DPO2U (Arquitetura Compact/Midnight)
 * Focado na privacidade e preservação de dados:
 * Nunca registrar dados sensiveis. Apenas hashes de docs (CID), DIDs de agentes responsaveis e o score zk final.
 */
pragma language_version >= 0.19;
import CompactStandardLibrary;

export ledger attestation_scores: Map<Bytes<32>, Uint<64>>;
export ledger attestation_dids: Map<Bytes<32>, Bytes<32>>;
export ledger attestation_cids: Map<Bytes<32>, Bytes<32>>;

export ledger attestation_score: Uint<64>;

export circuit registerAttestation(
  company_id: Bytes<32>,
  agent_did: Bytes<32>,
  policy_cid: Bytes<32>,
  score: Uint<64>
): [] {
  assert(score <= 100, "Invalid compliance score, must be bounded to 0-100%");

  // Update global ledger state
  attestation_scores.insert(disclose(company_id), disclose(score));
  attestation_dids.insert(disclose(company_id), disclose(agent_did));
  attestation_cids.insert(disclose(company_id), disclose(policy_cid));

  // Also store the latest global score for simpler testing queries
  attestation_score = disclose(score);
}

export circuit getComplianceStatus(company_id: Bytes<32>): Uint<64> {
  return attestation_score;
}

/**
 * Payment Gateway & Treasury DPO2U
 * Ponto de entrada para depósitos escrow de Empresas e liberação fiduciária
 */
pragma language_version >= 0.19;
import CompactStandardLibrary;

export ledger protocol_treasury: Uint<64>;
export ledger total_staked_night: Uint<64>;

export circuit depositToTreasury(amount: Uint<64>): [] {
  assert(amount > 0, "Deposit must be greater than zero");
  protocol_treasury = disclose(amount);
}

export circuit stakeTokens(amount: Uint<64>): [] {
  assert(amount > 0, "Stake must be greater than zero");
  total_staked_night = disclose(amount);
}

export circuit getTreasuryBalance(): Uint<64> {
  return protocol_treasury;
}

/**
 * Fee Distributor DPO2U (Arquitetura Compact/Midnight)
 * Responsável por orquestrar repasses de valores do Protocolo B2B para $NIGHT (Self-Funding).
 * Split 40/60: expert_share + auditor_share são computados off-chain e validados on-chain.
 * O contrato verifica que expert_share + auditor_share == total_amount (constraint ZK).
 */
pragma language_version >= 0.19;
import CompactStandardLibrary;

export ledger expert_fee_pool: Uint<64>;
export ledger auditor_fee_pool: Uint<64>;

export circuit distributeComplianceFee(
  company_id: Bytes<32>,
  expert_agent_did: Bytes<32>,
  auditor_agent_did: Bytes<32>,
  total_amount: Uint<64>,
  expert_share: Uint<64>,
  auditor_share: Uint<64>
): [] {
  assert(total_amount > 0, "Fee must be greater than zero");
  // ZK constraint: shares must sum to total (40/60 split enforced off-chain)
  assert(expert_share + auditor_share == total_amount, "Shares must sum to total amount");

  expert_fee_pool = disclose(expert_share);
  auditor_fee_pool = disclose(auditor_share);
}

export circuit getAuditorPools(): Uint<64> {
  return auditor_fee_pool;
}

export circuit getExpertPools(): Uint<64> {
  return expert_fee_pool;
}
